mapper.insert:
insert into tbl_oauth (
    member_id, provider, provider_id
) values (
    #{memberId}, #{provider}, #{providerId}
)

mapper.select:
select
    id, member_id, provider, provider_id, connected_at
from tbl_oauth
where provider = #{provider}
  and provider_id = #{providerId}
  and deleted_datetime is null

select
    id, member_id, provider, provider_id, connected_at
from tbl_oauth
where member_id = #{memberId}
  and provider = #{provider}
  and deleted_datetime is null
